            // addUnit(data, setserverOperationError, setServerOperationLoading, setAllUnit)
        }
    }
    // add school func end  

    return (
        <div className='school-container'>
             <div className='new-school'>
                <div className='d-flex align-items-center'>
                    <span className='add-icon'>+</span>
                    <p onClick={openAddSchoolPopup}>Add New School</p>
                </div>
            </div>
            <div className="school-cover d-flex justify-content-space-between">
                <p>test</p>
                <div>
                    <i className="fa fa-pencil" aria-hidden="true"></i>
                    <i className="fa fa-trash-o" aria-hidden="true"></i>
                </div>
            </div>
            {/* delete unit popup start */}
            <div className="add-school-popup school-popup d-none justify-content-center align-items-center">
                    <div>
                        <p className='text-color'>Add new school account</p>
